import{_ as a,o as t,c as o,a3 as r}from"./chunks/framework.CjquFG0V.js";const l=JSON.parse('{"title":"15. Cooking Trade Proficiency Payments","description":"","frontmatter":{"title":"15. Cooking Trade Proficiency Payments","eba":"Health Allied & Managers Admin 2021-2025","topics":["wages","training"]},"headers":[],"relativePath":"ebas/has-managers-admin/health-allied-services/allowances/15-cooking-trade-proficiency-payments.md","filePath":"ebas/has-managers-admin/health-allied-services/allowances/15-cooking-trade-proficiency-payments.md"}'),s={name:"ebas/has-managers-admin/health-allied-services/allowances/15-cooking-trade-proficiency-payments.md"};function n(i,e,c,h,p,d){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="_15-cooking-trade-proficiency-payments" tabindex="-1">15. Cooking Trade Proficiency Payments <a class="header-anchor" href="#_15-cooking-trade-proficiency-payments" aria-label="Permalink to &quot;15. Cooking Trade Proficiency Payments&quot;">​</a></h1><p><strong>15.1</strong> This proficiency pay scheme applies to apprentices who started attending trade class from 1979 and who have undertaken the standard cooking course and attained the standard of proficiency.</p><p><strong>15.2</strong> This proficiency pay scheme does not apply to apprentices who have undertaken the pilot course conducted at William Angliss College in 1983.</p><p><strong>15.3</strong> Standard of Proficiency Apprentices will have reached the standard of proficiency in each year of the course when they have passed in the first, second and third years the subjects prescribed from time to time by the Victorian Registration and Qualifications Authority and attained an average mark of not less than 70 per cent for those subjects. The subjects must be passed at the first attempt.</p><p><strong>15.4</strong> Proficiency Pay This scheme provides for the payment of tradesperson’s rates of pay to apprentices during the fourth year of the apprenticeship where the standard of proficiency has been attained on one, two or three occasions on the following basis:</p><p>SECTION 2 – HEALTH &amp; ALLIED SERVICES EMPLOYEES AND DENTAL ASSISTANTS</p><p><strong>(a)</strong> on one occasion only – for the first nine months of the fourth year of the apprenticeship, the normal fourth year rate of pay. Thereafter, the “Trade Cook” rate of pay pursuant to Part 1 of <a href="/eba/ebas/has-managers-admin/schedules/2b-wage-rates-health-allied-services.html">Schedule 2B</a>.</p><p><strong>(b)</strong> on two occasions – for the first six months of the fourth year of the apprenticeship, the normal fourth year rate of pay. Thereafter, the “Trade Cook” rate of pay pursuant to Part 1 of <a href="/eba/ebas/has-managers-admin/schedules/2b-wage-rates-health-allied-services.html">Schedule 2B</a>.</p><p><strong>(c)</strong> on all three occasions – for the entire fourth year at the “Trade Cook” rate of pay pursuant to Part 1 of <a href="/eba/ebas/has-managers-admin/schedules/2b-wage-rates-health-allied-services.html">Schedule 2B</a>.</p>',9)])])}const m=a(s,[["render",n]]);export{l as __pageData,m as default};
